import Fastify from 'fastify'
import websocket from '@fastify/websocket'
import cors from '@fastify/cors'
import { getServices } from './services'

export async function startDashboard(port: number = 3000) {
  const app = Fastify({
    logger: true
  })

  // 注册插件
  await app.register(cors)
  await app.register(websocket)

  // 获取服务实例
  const { iterationService, agentService, realtimeService } = getServices()

  // 健康检查
  app.get('/health', async () => ({ status: 'ok', timestamp: Date.now() }))

  // 系统概览
  app.get('/api/system/overview', async () => {
    return iterationService.getOverview()
  })

  // 迭代列表
  app.get('/api/iterations', async (request) => {
    const { page = 1, limit = 20, status } = request.query as any
    return iterationService.list({ page, limit, status })
  })

  // 迭代详情
  app.get('/api/iterations/:id', async (request) => {
    const { id } = request.params as { id: string }
    return iterationService.getById(id)
  })

  // Agent 状态
  app.get('/api/agents', async () => {
    return agentService.getAllStates()
  })

  // WebSocket 连接
  app.register(async function (fastify) {
    fastify.get('/api/ws', { websocket: true }, (connection) => {
      realtimeService.addClient(connection)

      connection.socket.on('message', (message) => {
        const { event, data } = JSON.parse(message.toString())
        // 处理客户端消息
      })

      connection.socket.on('close', () => {
        realtimeService.removeClient(connection)
      })
    })
  })

  await app.listen({ port, host: '0.0.0.0' })
  console.log(`Dashboard server running on http://localhost:${port}`)
}
```

